import os
import sys
import json
import argparse
import torch
from torchvision import transforms
from PIL import Image
from torch.utils.data import Dataset, DataLoader
import numpy as np

# Support both DINOv2 and CLIP models
def load_dinov2_model(checkpoint_path, device):
    from model import WildlifeClassifier
    checkpoint = torch.load(checkpoint_path, map_location=device, weights_only=False)
    config = checkpoint.get('config', {'use_dann': True, 'use_mixstyle': False})
    model = WildlifeClassifier(
        num_classes=10,
        freeze_backbone=False,
        use_dann=config.get('use_dann', True),
        use_mixstyle=config.get('use_mixstyle', False)
    )
    if 'ema_state_dict' in checkpoint:
        state_dict = checkpoint['ema_state_dict']
    elif 'model_state_dict' in checkpoint:
        state_dict = checkpoint['model_state_dict']
    else:
        state_dict = checkpoint
    model_dict = model.state_dict()
    filtered = {k: v for k, v in state_dict.items() if k in model_dict and v.shape == model_dict[k].shape}
    model_dict.update(filtered)
    model.load_state_dict(model_dict)
    model = model.to(device)
    model.eval()
    return model

def load_clip_model(checkpoint_path, device):
    from clip_model import CLIPClassifier
    checkpoint = torch.load(checkpoint_path, map_location=device, weights_only=False)
    model = CLIPClassifier(num_classes=10, freeze_backbone=False, use_dann=True)
    if 'ema_state_dict' in checkpoint:
        state_dict = checkpoint['ema_state_dict']
    elif 'model_state_dict' in checkpoint:
        state_dict = checkpoint['model_state_dict']
    else:
        state_dict = checkpoint
    model_dict = model.state_dict()
    filtered = {k: v for k, v in state_dict.items() if k in model_dict and v.shape == model_dict[k].shape}
    model_dict.update(filtered)
    model.load_state_dict(model_dict)
    model = model.to(device)
    model.eval()
    return model

class TestDataset(Dataset):
    def __init__(self, data_path, transform=None):
        self.data_dir = os.path.abspath(data_path)
        self.transform = transform
        self.samples = []

        # Try to find test.txt
        test_file = None
        candidates = [os.path.join(self.data_dir, 'test.txt')]

        # Search subdirectories too
        try:
            for root, dirs, files in os.walk(self.data_dir):
                for f in files:
                    if f == 'test.txt':
                        p = os.path.join(root, f)
                        if p not in candidates:
                            candidates.append(p)
        except:
            pass

        for p in candidates:
            if os.path.exists(p):
                test_file = p
                break

        if test_file is not None:
            with open(test_file, 'r') as f:
                for line in f:
                    line = line.strip()
                    if line:
                        self.samples.append(line.split()[0])
            print(f'Loaded {len(self.samples)} samples from {test_file}')
        else:
            print(f'WARNING: test.txt not found in {self.data_dir}')
            if os.path.exists(self.data_dir):
                print(f'Contents: {os.listdir(self.data_dir)[:20]}')
            img_dir = os.path.join(self.data_dir, 'images')
            if os.path.exists(img_dir):
                for root, dirs, files in os.walk(img_dir):
                    dirs.sort()
                    for f in sorted(files):
                        if f.lower().endswith(('.jpg', '.jpeg', '.png')):
                            rel = os.path.relpath(os.path.join(root, f), img_dir)
                            self.samples.append(rel)
                print(f'Found {len(self.samples)} images by walking (FALLBACK)')

    def __len__(self):
        return len(self.samples)

    def __getitem__(self, idx):
        rel_path = self.samples[idx]
        for base in [os.path.join(self.data_dir, 'images'), self.data_dir]:
            img_path = os.path.join(base, rel_path)
            if os.path.exists(img_path):
                try:
                    img = Image.open(img_path).convert('RGB')
                    if self.transform:
                        img = self.transform(img)
                    return img
                except:
                    pass
        img = Image.new('RGB', (224, 224), (0, 0, 0))
        if self.transform:
            img = self.transform(img)
        return img

def predict_with_model(model, dataset, device, batch_size=64, num_tta=4):
    normalize = transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
    tta_transforms = [
        transforms.Compose([transforms.Resize((224, 224)), transforms.ToTensor(), normalize]),
        transforms.Compose([transforms.Resize((224, 224)), transforms.RandomHorizontalFlip(p=1.0), transforms.ToTensor(), normalize]),
        transforms.Compose([transforms.Resize(256), transforms.CenterCrop(224), transforms.ToTensor(), normalize]),
        transforms.Compose([transforms.Resize(256), transforms.CenterCrop(224), transforms.RandomHorizontalFlip(p=1.0), transforms.ToTensor(), normalize]),
    ][:num_tta]

    all_probs = None
    for t_idx, transform in enumerate(tta_transforms):
        dataset.transform = transform
        loader = DataLoader(dataset, batch_size=batch_size, num_workers=4, pin_memory=True)
        probs_list = []
        with torch.no_grad():
            for images in loader:
                images = images.to(device)
                logits = model(images)
                probs = torch.softmax(logits, dim=1)
                probs_list.append(probs.cpu().numpy())
        probs = np.concatenate(probs_list, axis=0)
        if all_probs is None:
            all_probs = probs.copy()
        else:
            all_probs += probs
    all_probs /= len(tta_transforms)
    return all_probs

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    parser.add_argument('--batch_size', type=int, default=64)
    args = parser.parse_args()

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')

    # Determine model type from checkpoint
    checkpoint = torch.load(args.checkpoint, map_location='cpu', weights_only=False)
    config = checkpoint.get('config', {})
    backbone = config.get('backbone', 'dinov2')

    if backbone == 'clip':
        model = load_clip_model(args.checkpoint, device)
    else:
        model = load_dinov2_model(args.checkpoint, device)

    dataset = TestDataset(args.data_path)
    probs = predict_with_model(model, dataset, device, args.batch_size)
    predictions = np.argmax(probs, axis=1).tolist()

    with open(args.output, 'w') as f:
        json.dump({"predictions": predictions}, f)
    print(f'Saved {len(predictions)} predictions to {args.output}')

if __name__ == '__main__':
    main()
